10: pub fn NodePoolType(comptime _node_size: u32, comptime _node_alignment: u13) type {
11:     return struct {
12:         const NodePool = @This();
13: 
14:         pub const node_size = _node_size;
15:         pub const node_alignment = _node_alignment;
16:         pub const Node = *align(node_alignment) [node_size]u8;
17: 
18:         comptime {
19:             assert(node_size > 0);
20:             assert(node_alignment > 0);
21:             assert(node_alignment <= 4096);
22:             assert(math.isPowerOfTwo(node_size));
23:             assert(math.isPowerOfTwo(node_alignment));
24:             assert(node_size % node_alignment == 0);
25:         }
26: 
27:         buffer: []align(node_alignment) u8,
28:         free: std.bit_set.DynamicBitSetUnmanaged,
29: 
30:         pub fn init(pool: *NodePool, allocator: mem.Allocator, node_count: u32) !void {
31:             assert(node_count > 0);
32: 
33:             pool.* = .{
34:                 .buffer = undefined,
35:                 .free = undefined,
36:             };
37:             const size = node_size * node_count;
38:             pool.buffer = try allocator.alignedAlloc(u8, node_alignment, size);
39:             errdefer allocator.free(pool.buffer);
40: 
41:             pool.free = try std.bit_set.DynamicBitSetUnmanaged.initFull(allocator, node_count);
42:             errdefer pool.free.deinit(allocator);
43:         }
44: 
45:         pub fn deinit(pool: *NodePool, allocator: mem.Allocator) void {
46:             // If the NodePool is being deinitialized, all nodes should have already been
47:             // released to the pool.
48:             assert(pool.free.count() == pool.free.bit_length);
49: 
50:             allocator.free(pool.buffer);
51:             pool.free.deinit(allocator);
52:         }
53: 
54:         pub fn acquire(pool: *NodePool) Node {
55:             // TODO: To ensure this "unreachable" is never reached, the primary must reject
56:             // new requests when storage space is too low to fulfill them.
57:             const node_index = pool.free.findFirstSet() orelse vsr.fatal(
58:                 .manifest_node_pool_exhausted,
59:                 "out of memory for manifest, " ++
60:                     "restart the replica increasing '--memory-lsm-manifest'",
61:                 .{},
62:             );
63:             assert(pool.free.isSet(node_index));
64:             pool.free.unset(node_index);
65: 
66:             const node = pool.buffer[node_index * node_size ..][0..node_size];
67:             return @alignCast(node);
68:         }
69: 
70:         pub fn release(pool: *NodePool, node: Node) void {
71:             // Our pointer arithmetic assumes that the unit of node_size is a u8.
72:             comptime assert(meta.Elem(Node) == u8);
73:             comptime assert(meta.Elem(@TypeOf(pool.buffer)) == u8);
74: 
75:             assert(@intFromPtr(node) >= @intFromPtr(pool.buffer.ptr));
76:             assert(@intFromPtr(node) + node_size <= @intFromPtr(pool.buffer.ptr) + pool.buffer.len);
77: 
78:             const node_offset = @intFromPtr(node) - @intFromPtr(pool.buffer.ptr);
79:             const node_index = @divExact(node_offset, node_size);
80:             assert(!pool.free.isSet(node_index));
81:             pool.free.set(node_index);
82:         }
83:     };
84: }
