86: fn TestContextType(comptime node_size: usize, comptime node_alignment: u12) type {
87:     const testing = std.testing;
88:     const TestPool = NodePoolType(node_size, node_alignment);
89: 
90:     const log = false;
91: 
92:     return struct {
93:         const TestContext = @This();
94: 
95:         node_count: u32,
96:         prng: *stdx.PRNG,
97:         sentinel: u64,
98:         node_pool: TestPool,
99:         node_map: std.AutoArrayHashMap(TestPool.Node, u64),
100: 
101:         acquires: u64 = 0,
102:         releases: u64 = 0,
103: 
104:         fn init(context: *TestContext, prng: *stdx.PRNG, node_count: u32) !void {
105:             context.* = .{
106:                 .node_count = node_count,
107:                 .prng = prng,
108:                 .sentinel = prng.int(u64),
109: 
110:                 .node_pool = undefined,
111:                 .node_map = undefined,
112:             };
113: 
114:             try context.node_pool.init(testing.allocator, node_count);
115:             errdefer context.node_pool.deinit(testing.allocator);
116:             @memset(mem.bytesAsSlice(u64, context.node_pool.buffer), context.sentinel);
117: 
118:             context.node_map = std.AutoArrayHashMap(TestPool.Node, u64).init(testing.allocator);
119:             errdefer context.node_map.deinit();
120:         }
121: 
122:         fn deinit(context: *TestContext) void {
123:             context.node_pool.deinit(testing.allocator);
124:             context.node_map.deinit();
125:         }
126: 
127:         fn run(context: *TestContext) !void {
128:             const Action = enum { acquire, release };
129:             {
130:                 var i: usize = 0;
131:                 while (i < context.node_count * 4) : (i += 1) {
132:                     switch (context.prng.enum_weighted(Action, .{
133:                         .acquire = 60,
134:                         .release = 40,
135:                     })) {
136:                         .acquire => try context.acquire(),
137:                         .release => try context.release(),
138:                     }
139:                 }
140:             }
141: 
142:             {
143:                 var i: usize = 0;
144:                 while (i < context.node_count * 4) : (i += 1) {
145:                     switch (context.prng.enum_weighted(Action, .{
146:                         .acquire = 40,
147:                         .release = 60,
148:                     })) {
149:                         .acquire => try context.acquire(),
150:                         .release => try context.release(),
151:                     }
152:                 }
153:             }
154: 
155:             try context.release_all();
156:         }
157: 
158:         fn acquire(context: *TestContext) !void {
159:             if (context.node_map.count() == context.node_count) return;
160: 
161:             const node = context.node_pool.acquire();
162: 
163:             // Verify that this node has not already been acquired.
164:             for (mem.bytesAsSlice(u64, node)) |word| {
165:                 try testing.expectEqual(context.sentinel, word);
166:             }
167: 
168:             const gop = try context.node_map.getOrPut(node);
169:             try testing.expect(!gop.found_existing);
170: 
171:             // Write unique data into the node so we can test that it doesn't get overwritten.
172:             const id = context.prng.int(u64);
173:             @memset(mem.bytesAsSlice(u64, node), id);
174:             gop.value_ptr.* = id;
175: 
176:             context.acquires += 1;
177:         }
178: 
179:         fn release(context: *TestContext) !void {
180:             if (context.node_map.count() == 0) return;
181: 
182:             const index = context.prng.index(context.node_map.keys());
183:             const node = context.node_map.keys()[index];
184:             const id = context.node_map.values()[index];
185: 
186:             // Verify that the data of this node has not been overwritten since we acquired it.
187:             for (mem.bytesAsSlice(u64, node)) |word| {
188:                 try testing.expectEqual(id, word);
189:             }
190: 
191:             @memset(mem.bytesAsSlice(u64, node), context.sentinel);
192:             context.node_pool.release(node);
193:             context.node_map.swapRemoveAt(index);
194: 
195:             context.releases += 1;
196:         }
197: 
198:         fn release_all(context: *TestContext) !void {
199:             while (context.node_map.count() > 0) try context.release();
200: 
201:             // Verify that nothing in the entire buffer has been acquired.
202:             for (mem.bytesAsSlice(u64, context.node_pool.buffer)) |word| {
203:                 try testing.expectEqual(context.sentinel, word);
204:             }
205: 
206:             if (log) {
207:                 std.debug.print("\nacquires: {}, releases: {}\n", .{
208:                     context.acquires,
209:                     context.releases,
210:                 });
211:             }
212: 
213:             try testing.expect(context.acquires > 0);
214:             try testing.expect(context.acquires == context.releases);
215:         }
216:     };
217: }
