2: //!
3: //! Note that a AOF-recovered cluster is *not* physically identical to the original cluster.
4: //! It should be logically identical though -- the same data (minus the client table), just in
5: //! different places.
6: const std = @import("std");
7: const assert = std.debug.assert;
8: 
9: const constants = @import("constants.zig");
10: const vsr = @import("vsr.zig");
11: const tb = vsr.tigerbeetle;
12: 
13: const stdx = @import("stdx");
14: const MessagePool = vsr.message_pool.MessagePool;
15: const Message = MessagePool.Message;
16: const MessageBus = vsr.message_bus.MessageBusType(vsr.io.IO);
17: const Header = vsr.Header;
18: 
19: const MiB = stdx.MiB;
20: 
21: const log = std.log.scoped(.aof);
22: 
23: pub const std_options: std.Options = .{
24:     .log_level = .info,
25:     .logFn = stdx.log_with_timestamp,
26: };
27: 
28: const magic_number: u128 = 0xbcd8d3fee406119ed192c4f4c4fc82;
29: 
30: pub const AOFEntry = extern struct {
31:     /// In case of extreme corruption, start each entry with a fixed random integer,
32:     /// to allow skipping over corrupted entries.
33:     magic_number: u128 = magic_number,
34: 
35:     /// The main Message to log. This is written _without_ O_DIRECT, so sector alignment is not
36:     /// a concern.
37:     message: [constants.message_size_max]u8 align(16),
38: 
39:     comptime {
40:         assert(stdx.no_padding(AOFEntry));
41: 
42:         // Ensure the message is the last field in the struct. When writing, the struct is truncated
43:         // based on the message length, so any fields after it would be truncated.
44:         assert(std.meta.fieldIndex(AOFEntry, "message").? == std.meta.fields(AOFEntry).len - 1);
45:     }
46: 
47:     /// Calculate the actual length of the AOFEntry that needs to be written to disk.
48:     pub fn size_disk(self: *AOFEntry) u64 {
49:         return @sizeOf(AOFEntry) - self.message.len + self.header().size;
50:     }
51: 
52:     /// The minimum size of an AOFEntry is when `message` is a Header with no body.
53:     pub fn size_minimum(self: *AOFEntry) u64 {
54:         return @sizeOf(AOFEntry) - self.message.len + @sizeOf(Header);
55:     }
56: 
57:     pub fn header(self: *AOFEntry) *Header.Prepare {
58:         return @ptrCast(&self.message);
59:     }
60: 
61:     /// Turn an AOFEntry back into a Message.
62:     pub fn to_message(self: *AOFEntry, target: *Message.Prepare) void {
63:         stdx.copy_disjoint(.inexact, u8, target.buffer, self.message[0..self.header().size]);
64:     }
65: 
66:     pub fn from_message(
67:         self: *AOFEntry,
68:         message: *const Message.Prepare,
69:         last_checksum: *?u128,
70:     ) void {
71:         assert(message.header.size <= self.message.len);
72: 
73:         // When writing, entries can backtrack / duplicate, so we don't necessarily have a valid
74:         // chain. Still, log when that happens. The `aof merge` command can generate a consistent
75:         // file from entries like these.
76:         log.debug("from_message: parent {x:0>32} (should == {x:0>32}) our checksum {x:0>32}", .{
77:             message.header.parent,
78:             last_checksum.* orelse 0,
79:             message.header.checksum,
80:         });
81:         if (last_checksum.* == null or last_checksum.*.? != message.header.parent) {
82:             log.info("from_message: parent {x:0>32}, expected {x:0>32} instead", .{
83:                 message.header.parent,
84:                 last_checksum.* orelse 0,
85:             });
86:         }
87:         last_checksum.* = message.header.checksum;
88: 
89:         // The cluster identifier is in the VSR header so we don't need to store it explicitly.
90:         // The replica that this was logged on will be the replica with this file. If uploaded to
91:         // object storage, this must be embedded in the filename or path.
92:         // Whether this replica is the primary can be determined by the view number from the
93:         // relevant op.
94:         comptime {
95:             const fields = std.meta.fieldNames(AOFEntry);
96:             assert(fields.len == 2);
97:             assert(std.mem.eql(u8, fields[0], "magic_number"));
98:             assert(std.mem.eql(u8, fields[1], "message"));
99:         }
100: 
101:         // Using self.* = .{ .message = undefined } notation causes a `constants.message_size_max`
102:         // increase in binary size, since Zig embeds the entire static initialization payload in the
103:         // binary.
104:         self.* = undefined;
105:         self.magic_number = magic_number;
106:         stdx.copy_disjoint(
107:             .exact,
108:             u8,
109:             self.message[0..message.header.size],
110:             message.buffer[0..message.header.size],
111:         );
112:         @memset(self.message[message.header.size..self.message.len], 0);
113:     }
114: };
