14: /// Holds memory for performing scans on all lsm tree levels.
15: /// TODO: It may be removed once we have ref-counted grid blocks.
16: pub const ScanBuffer = struct {
17:     pub const LevelBuffer = struct {
18:         index_block: BlockPtr,
19:         value_block: BlockPtr,
20: 
21:         pub fn init(self: *LevelBuffer, allocator: Allocator) !void {
22:             self.* = .{
23:                 .index_block = undefined,
24:                 .value_block = undefined,
25:             };
26: 
27:             self.index_block = try allocate_block(allocator);
28:             errdefer allocator.free(self.index_block);
29: 
30:             self.value_block = try allocate_block(allocator);
31:             errdefer allocator.free(self.value_block);
32:         }
33: 
34:         pub fn deinit(self: *LevelBuffer, allocator: Allocator) void {
35:             allocator.free(self.index_block);
36:             allocator.free(self.value_block);
37:         }
38:     };
39: 
40:     index: u8,
41:     levels: [constants.lsm_levels]LevelBuffer,
42: 
43:     pub fn init(
44:         self: *ScanBuffer,
45:         allocator: Allocator,
46:         options: struct {
47:             index: u8,
48:         },
49:     ) !void {
50:         self.* = .{
51:             .index = options.index,
52:             .levels = undefined,
53:         };
54:         for (&self.levels, 0..) |*level, i| {
55:             errdefer for (self.levels[0..i]) |*level_| level_.deinit(allocator);
56:             try level.init(allocator);
57:         }
58:         errdefer for (&self.levels) |*level| level.deinit(allocator);
59:     }
60: 
61:     pub fn deinit(self: *ScanBuffer, allocator: Allocator) void {
62:         for (&self.levels) |*level| {
63:             level.deinit(allocator);
64:         }
65:     }
66: };
