68: /// ScanBufferPool holds enough memory to perform up to a max number of
69: /// scans operations in parallel.
70: /// This buffer is shared across different trees.
71: /// TODO: It may be removed once we have ref-counted grid blocks.
72: pub const ScanBufferPool = struct {
73:     scan_buffers: [constants.lsm_scans_max]ScanBuffer,
74:     scan_buffer_used: u8,
75: 
76:     pub fn init(self: *ScanBufferPool, allocator: Allocator) !void {
77:         self.* = .{
78:             .scan_buffers = undefined,
79:             .scan_buffer_used = 0,
80:         };
81: 
82:         for (&self.scan_buffers, 0..) |*scan_buffer, index| {
83:             errdefer for (self.scan_buffers[0..index]) |*buffer| buffer.deinit(allocator);
84:             try scan_buffer.init(
85:                 allocator,
86:                 .{ .index = @intCast(index) },
87:             );
88:         }
89:         errdefer for (&self.scan_buffers) |*buffer| buffer.deinit(allocator);
90:     }
91: 
92:     pub fn deinit(self: *ScanBufferPool, allocator: Allocator) void {
93:         for (&self.scan_buffers) |*scan_buffer| {
94:             scan_buffer.deinit(allocator);
95:         }
96:     }
97: 
98:     pub fn reset(self: *ScanBufferPool) void {
99:         self.* = .{
100:             .scan_buffers = self.scan_buffers,
101:             .scan_buffer_used = 0,
102:         };
103:     }
104: 
105:     pub fn acquire(self: *ScanBufferPool) Error!*const ScanBuffer {
106:         if (self.scan_buffer_used == constants.lsm_scans_max) return Error.ScansMaxExceeded;
107: 
108:         defer self.scan_buffer_used += 1;
109: 
110:         return &self.scan_buffers[self.scan_buffer_used];
111:     }
112: 
113:     pub fn acquire_assume_capacity(self: *ScanBufferPool) *const ScanBuffer {
114:         return self.acquire() catch unreachable;
115:     }
116: };
