120: pub inline fn copy_right(
121:     comptime precision: SizePrecision,
122:     comptime T: type,
123:     target: []T,
124:     source: []const T,
125: ) void {
126:     switch (precision) {
127:         .exact => assert(target.len == source.len),
128:         .inexact => assert(target.len >= source.len),
129:     }
130: 
131:     if (!disjoint_slices(T, T, target, source)) {
132:         assert(@intFromPtr(target.ptr) > @intFromPtr(source.ptr));
133:     }
134: 
135:     // (Bypass tidy's ban.)
136:     const copyBackwards = std.mem.copyBackwards;
137:     copyBackwards(T, target, source);
