149: pub inline fn copy_disjoint(
150:     comptime precision: SizePrecision,
151:     comptime T: type,
152:     target: []T,
153:     source: []const T,
154: ) void {
155:     switch (precision) {
156:         .exact => assert(target.len == source.len),
157:         .inexact => assert(target.len >= source.len),
158:     }
159: 
160:     // disjoint_slices() doesn't work in comptime, because of limitations with @intFromPtr:
161:     // https://github.com/ziglang/zig/issues/23072.
162:     //
163:     // It's also possible to construct slices into an array at comptime that are _not_ disjoint,
164:     // which would violate the intention of this function, so it can't just be skipped.
165:     assert(!@inComptime());
166:     assert(disjoint_slices(T, T, target, source));
167: 
168:     @memcpy // Bypass tidy ban.
169:     (target[0..source.len], source);
170: }
