172: pub inline fn disjoint_slices(comptime A: type, comptime B: type, a: []const A, b: []const B) bool {
173:     return @intFromPtr(a.ptr) + a.len * @sizeOf(A) <= @intFromPtr(b.ptr) or
174:         @intFromPtr(b.ptr) + b.len * @sizeOf(B) <= @intFromPtr(a.ptr);
175: }
