180: 
181:     const b = try std.testing.allocator.alloc(u32, 8);
182:     defer std.testing.allocator.free(b);
183: 
184:     try std.testing.expectEqual(true, disjoint_slices(u8, u32, a, b));
185:     try std.testing.expectEqual(true, disjoint_slices(u32, u8, b, a));
186: 
187:     try std.testing.expectEqual(true, disjoint_slices(u8, u8, a, a[0..0]));
188:     try std.testing.expectEqual(true, disjoint_slices(u32, u32, b, b[0..0]));
189: 
190:     try std.testing.expectEqual(false, disjoint_slices(u8, u8, a, a[0..1]));
191:     try std.testing.expectEqual(false, disjoint_slices(u8, u8, a, a[a.len - 1 .. a.len]));
192: 
193:     try std.testing.expectEqual(false, disjoint_slices(u32, u32, b, b[0..1]));
194:     try std.testing.expectEqual(false, disjoint_slices(u32, u32, b, b[b.len - 1 .. b.len]));
195: 
196:     try std.testing.expectEqual(false, disjoint_slices(u8, u32, a, std.mem.bytesAsSlice(u32, a)));
197:     try std.testing.expectEqual(false, disjoint_slices(u32, u8, b, std.mem.sliceAsBytes(b)));
198: }
