7: fn to_uppercase(comptime input: []const u8) []const u8 {
8:     comptime var uppercase: [input.len]u8 = undefined;
9:     inline for (input, 0..) |char, i| {
10:         const is_lowercase = (char >= 'a') and (char <= 'z');
11:         uppercase[i] = char - (@as(u8, @intFromBool(is_lowercase)) * 32);
12:     }
13:     return &uppercase;
14: }
15: 
16: fn to_snakecase(comptime input: []const u8) []const u8 {
17:     comptime var output: []const u8 = &.{};
18:     inline for (input, 0..) |char, i| {
19:         const is_uppercase = (char >= 'A') and (char <= 'Z');
20:         if (is_uppercase and i > 0) output = "_" ++ output;
21:         output = output ++ &[_]u8{char};
22:     }
23:     return output;
24: }
