45:         .{ exports.tb_init_status, "TB_INIT_STATUS" },
46:         .{ exports.tb_client_status, "TB_CLIENT_STATUS" },
47:         .{ exports.tb_packet_status, "TB_PACKET_STATUS" },
48:         .{ exports.tb_operation, "TB_OPERATION" },
49:         .{ exports.tb_register_log_callback_status, "TB_REGISTER_LOG_CALLBACK_STATUS" },
50:         .{ exports.tb_log_level, "TB_LOG_LEVEL" },
51:     }) |c_export| {
52:         const ty: type = c_export[0];
53:         const c_type_name = @as([]const u8, c_export[1]);
54:         const c_type: type = @field(c, c_type_name);
55: 
56:         switch (@typeInfo(ty)) {
57:             .int => assert(ty == c_type),
58:             .pointer => assert(@sizeOf(ty) == @sizeOf(c_type)),
59:             .@"enum" => {
60:                 const prefix_offset = std.mem.lastIndexOfScalar(u8, c_type_name, '_').?;
61:                 var c_enum_prefix: []const u8 = c_type_name[0 .. prefix_offset + 1];
62:                 assert(c_type == c_uint);
63: 
64:                 // TB_STATUS and TB_OPERATION are special cases in naming
65:                 if (std.mem.eql(u8, c_type_name, "TB_STATUS") or
66:                     std.mem.eql(u8, c_type_name, "TB_OPERATION"))
67:                 {
68:                     c_enum_prefix = c_type_name ++ "_";
69:                 }
70: 
71:                 // Compare the enum int values in C to the enum int values in Zig.
72:                 for (std.meta.fields(ty)) |field| {
73:                     if (std.mem.startsWith(u8, field.name, "deprecated_")) continue;
74:                     const c_enum_field = to_uppercase(to_snakecase(field.name));
75:                     const c_value = @field(c, c_enum_prefix ++ c_enum_field);
76: 
77:                     const zig_value = @intFromEnum(@field(ty, field.name));
78:                     assert(zig_value == c_value);
79:                 }
80:             },
81:             .@"struct" => |type_info| switch (type_info.layout) {
82:                 .auto => @compileError("struct must be extern or packed to be used in C"),
83:                 .@"packed" => {
84:                     const prefix_offset = std.mem.lastIndexOfScalar(u8, c_type_name, '_').?;
85:                     const c_enum_prefix = c_type_name[0 .. prefix_offset + 1];
86:                     assert(c_type == c_uint);
87: 
88:                     for (std.meta.fields(ty)) |field| {
89:                         if (!std.mem.eql(u8, field.name, "padding")) {
90:                             // Get the bit value in the C enum.
91:                             const c_enum_field = to_uppercase(to_snakecase(field.name));
92:                             const c_value = @field(c, c_enum_prefix ++ c_enum_field);
93: 
94:                             // Compare the bit value to the packed struct's field.
95:                             var instance = std.mem.zeroes(ty);
96:                             @field(instance, field.name) = true;
97:                             assert(@as(type_info.backing_integer.?, @bitCast(instance)) == c_value);
98:                         }
99:                     }
100:                 },
101:                 .@"extern" => {
102:                     // Ensure structs are effectively the same.
103:                     assert(@sizeOf(ty) == @sizeOf(c_type));
104:                     if (@alignOf(ty) != @alignOf(c_type)) {
105:                         @compileLog(ty, c_type);
106:                     }
107:                     assert(@alignOf(ty) == @alignOf(c_type));
108: 
109:                     for (std.meta.fields(ty)) |field| {
110:                         // In C, packed structs and enums are replaced with integers.
111:                         var field_type = field.type;
112:                         switch (@typeInfo(field_type)) {
113:                             .@"struct" => |info| {
114:                                 assert(info.layout == .@"packed");
115:                                 assert(@sizeOf(field_type) <= @sizeOf(u128));
116:                                 field_type = std.meta.Int(.unsigned, @bitSizeOf(field_type));
117:                             },
118:                             .@"enum" => |info| field_type = info.tag_type,
119:                             .bool => field_type = u8,
120:                             else => {},
121:                         }
122: 
123:                         // In C, pointers are opaque so we compare only the field sizes,
124:                         const c_field_type = @TypeOf(@field(@as(c_type, undefined), field.name));
125:                         switch (@typeInfo(c_field_type)) {
126:                             .pointer => |info| {
127:                                 assert(info.size == .c);
128:                                 assert(@sizeOf(c_field_type) == @sizeOf(field_type));
129:                             },
130:                             else => assert(c_field_type == field_type),
131:                         }
132:                     }
133:                 },
134:             },
135:             else => |i| @compileLog("TODO", i),
136:         }
137:     };
138: }
