25:         data: ?*anyopaque,
26:         data_size: u32,
27:         user_tag: u16,
28:         operation: u8,
29:         status: Status,
30:         @"opaque": [64]u8 = @splat(0),
31: 
32:         pub fn cast(self: *Extern) *Packet {
33:             return @ptrCast(self);
34:         }
35:     };
36: 
37:     const Phase = enum(u8) {
38:         submitted,
39:         pending,
40:         batched,
41:         sent,
42:         complete,
43:     };
