45:     pub const Queue = QueueType(Packet);
46: 
47:     user_data: ?*anyopaque,
48:     data: ?*anyopaque,
49:     data_size: u32,
50:     user_tag: u16,
51:     operation: u8,
52:     status: Status,
53: 
54:     link: Queue.Link,
