211: /// Similar to `std.mem.bytesAsSlice`, but allows buffers with inexact sizes,
212: /// returning the largest possible slice that is less than or equal to the buffer length.
213: /// Differently from `std.mem.bytesAsSlice` that can return `[]align(1) T`, this function
214: /// always `@alignCast` the result.
215: pub fn bytes_as_slice(
216:     comptime precision: SizePrecision,
217:     comptime T: type,
218:     bytes: anytype,
219: ) type: {
220:     const type_info = @typeInfo(@TypeOf(bytes));
221:     switch (type_info) {
222:         .pointer => |info| switch (info.size) {
223:             .one => switch (@typeInfo(info.child)) {
224:                 .array => |array_info| assert(array_info.child == u8),
225:                 else => unreachable,
226:             },
227:             .slice => assert(info.child == u8),
228:             else => unreachable,
229:         },
230:         else => unreachable,
231:     }
232: 
233:     break :type if (type_info.pointer.is_const) []const T else []T;
234: } {
235:     switch (precision) {
236:         .exact => {
237:             assert(bytes.len % @sizeOf(T) == 0);
238:             return @alignCast(std.mem.bytesAsSlice(T, bytes));
239:         },
240:         .inexact => {
241:             const size = @divFloor(bytes.len, @sizeOf(T)) * @sizeOf(T);
242:             return @alignCast(std.mem.bytesAsSlice(T, bytes[0..size]));
243:         },
244:     }
245: }
